import React from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
} from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { StackNavigationProp } from '@react-navigation/stack';
import { RootStackParamList } from '../types';

type DashboardScreenNavigationProp = StackNavigationProp<RootStackParamList, 'Dashboard'>;

export default function DashboardScreen() {
  const navigation = useNavigation<DashboardScreenNavigationProp>();

  const recentClaims = [
    {
      id: '1',
      title: 'Front Body Damage',
      policy: 'Claim ref. #MOT-8852',
      status: 'IN REVIEW',
      statusColor: '#F2994A',
      date: 'Dec 10',
    },
    {
      id: '2',
      title: 'Minor Body Damage',
      policy: 'Claim ref. #CLM-7762',
      status: 'SETTLED',
      statusColor: '#27AE60',
      date: 'Sep 15',
    },
  ];

  return (
    <View style={styles.container}>
      <ScrollView contentContainerStyle={styles.scroll}>
        <View style={styles.header}>
          <View>
            <Text style={styles.appName}>MotorIQ</Text>
            <Text style={styles.welcomeText}>Welcome back</Text>
          </View>
          <View style={styles.avatar} />
        </View>

        <TouchableOpacity
          style={styles.primaryButton}
          onPress={() => navigation.navigate('ReportAccident')}
        >
          <Text style={styles.primaryButtonText}>Report an Incident</Text>
        </TouchableOpacity>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Active Policy</Text>
          <View style={styles.policyCard}>
            <View style={styles.policyHeader}>
              <View style={styles.statusBadge}>
                <Text style={styles.statusBadgeText}>ACTIVE</Text>
              </View>
              <Text style={styles.manageText}>Manage</Text>
            </View>
            <Text style={styles.policyTitle}>Comprehensive Car Insurance</Text>
            <View style={styles.policyRow}>
              <View>
                <Text style={styles.policyLabel}>Policy Number</Text>
                <Text style={styles.policyValue}>ABC-12345789</Text>
              </View>
              <View>
                <Text style={styles.policyLabel}>Coverage Limit</Text>
                <Text style={styles.policyValue}>$50,000</Text>
              </View>
            </View>
            <View style={styles.policyFooter}>
              <Text style={styles.policyFooterText}>Renews Dec 12, 2026</Text>
              <Text style={styles.viewPolicy}>View Policy</Text>
            </View>
          </View>
        </View>

        <View style={styles.section}>
          <View style={styles.sectionHeaderRow}>
            <Text style={styles.sectionTitle}>Recent Claims</Text>
            <Text style={styles.linkText}>History</Text>
          </View>
          {recentClaims.map((claim) => (
            <View key={claim.id} style={styles.claimCard}>
              <View style={styles.claimLeft}>
                <View style={styles.claimIcon} />
              </View>
              <View style={styles.claimMiddle}>
                <Text style={styles.claimTitle}>{claim.title}</Text>
                <Text style={styles.claimSubtitle}>{claim.policy}</Text>
                <Text
                  style={[
                    styles.claimStatus,
                    { color: claim.statusColor },
                  ]}
                >
                  {claim.status}
                </Text>
              </View>
              <View style={styles.claimRight}>
                <Text style={styles.claimDate}>{claim.date}</Text>
              </View>
            </View>
          ))}
        </View>
      </ScrollView>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F7F9FC',
  },
  scroll: {
    paddingHorizontal: 20,
    paddingTop: 20,
    paddingBottom: 24,
  },
  header: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 24,
  },
  appName: {
    fontSize: 20,
    fontWeight: '700',
    color: '#0B1020',
  },
  welcomeText: {
    fontSize: 14,
    color: '#8F9BB3',
    marginTop: 4,
  },
  avatar: {
    width: 36,
    height: 36,
    borderRadius: 18,
    backgroundColor: '#EDF1F7',
  },
  primaryButton: {
    backgroundColor: '#111827',
    borderRadius: 12,
    paddingVertical: 14,
    alignItems: 'center',
    marginBottom: 24,
  },
  primaryButtonText: {
    color: '#FFFFFF',
    fontSize: 16,
    fontWeight: '600',
  },
  section: {
    marginBottom: 24,
  },
  sectionTitle: {
    fontSize: 16,
    fontWeight: '600',
    color: '#1F2937',
    marginBottom: 12,
  },
  sectionHeaderRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 12,
  },
  linkText: {
    fontSize: 13,
    color: '#4B5563',
  },
  policyCard: {
    backgroundColor: '#111827',
    borderRadius: 16,
    padding: 16,
  },
  policyHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 12,
  },
  statusBadge: {
    paddingHorizontal: 10,
    paddingVertical: 4,
    borderRadius: 20,
    backgroundColor: '#10B981',
  },
  statusBadgeText: {
    color: '#FFFFFF',
    fontSize: 11,
    fontWeight: '600',
  },
  manageText: {
    color: '#E5E7EB',
    fontSize: 12,
  },
  policyTitle: {
    color: '#FFFFFF',
    fontSize: 16,
    fontWeight: '600',
    marginBottom: 12,
  },
  policyRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    marginBottom: 12,
  },
  policyLabel: {
    color: '#9CA3AF',
    fontSize: 11,
    marginBottom: 2,
  },
  policyValue: {
    color: '#F9FAFB',
    fontSize: 13,
    fontWeight: '600',
  },
  policyFooter: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginTop: 4,
  },
  policyFooterText: {
    color: '#9CA3AF',
    fontSize: 11,
  },
  viewPolicy: {
    color: '#E5E7EB',
    fontSize: 12,
    fontWeight: '600',
  },
  claimCard: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: '#FFFFFF',
    borderRadius: 12,
    padding: 12,
    marginBottom: 10,
  },
  claimLeft: {
    marginRight: 12,
  },
  claimIcon: {
    width: 40,
    height: 40,
    borderRadius: 12,
    backgroundColor: '#EEF2FF',
  },
  claimMiddle: {
    flex: 1,
  },
  claimTitle: {
    fontSize: 14,
    fontWeight: '600',
    color: '#111827',
  },
  claimSubtitle: {
    fontSize: 12,
    color: '#6B7280',
    marginTop: 2,
  },
  claimStatus: {
    fontSize: 12,
    fontWeight: '600',
    marginTop: 4,
  },
  claimRight: {
    marginLeft: 8,
  },
  claimDate: {
    fontSize: 12,
    color: '#9CA3AF',
  },
});
